```python
from mcp import mcp_tool
import requests

@mcp_tool
def create_order(api_version, cart_token=None, checkout_token=None, line_items=None, shipping_address=None, billing_address=None, inventory_behavior='bypass', send_receipt=False, send_fulfillment_receipt=False):
    url = f"https://your-shop-name.myshopify.com/admin/api/{api_version}/orders.json"
    headers = {
        "Content-Type": "application/json",
        "X-Shopify-Access-Token": "your-access-token"
    }

    data = {
        "order": {
            "cart_token": cart_token,
            "checkout_token": checkout_token,
            "line_items": line_items,
            "shipping_address": shipping_address,
            "billing_address": billing_address,
            "inventory_management": inventory_behavior,
            "send_receipt": send_receipt,
            "send_fulfillment_receipt": send_fulfillment_receipt
        }
    }

    response = requests.post(url, json=data, headers=headers)
    return response.json()
```

Make sure to replace `"https://your-shop-name.myshopify.com"` and `"your-access-token"` with the actual shop name and access token respectively. Also, ensure that the `line_items`, `shipping_address`, and `billing_address` are provided in the correct format as per the documentation.
